/**
 * Détecter PDF1 — sort 1 item par PDF
 * binary.pdf + json.sourceBinaryKey = 'pdf'
 */
const inputData = $input.all();
const out = [];

for (const item of inputData) {
  const j = item.json || {};
  const binAll = item.binary || {};
  const emailFrom = j.emailFrom ?? j.from ?? '';
  const emailSubject = j.emailSubject ?? j.subject ?? '';
  const emailDate = j.emailDate ?? j.date ?? new Date().toISOString();

  const keys = Object.keys(binAll || {}).filter(k => {
    const b = binAll[k];
    const mt = String(b?.mimeType || '').toLowerCase();
    const fn = String(b?.fileName || '').toLowerCase();
    return mt.includes('pdf') || /\.pdf$/i.test(fn);
  });

  if (keys.length === 0) {
    out.push({ json: { hasPdf: false, success: true, emailFrom, emailSubject, emailDate, message: 'Email sans PDF' } });
    continue;
  }

  for (const k of keys) {
    const b = binAll[k];
    const fileName = b.fileName || 'document.pdf';
    out.push({
      json: {
        hasPdf: true,
        success: true,
        sourceBinaryKey: 'pdf',
        pdfFileName: fileName,
        pdfMimeType: b.mimeType || 'application/pdf',
        emailFrom, emailSubject, emailDate,
      },
      binary: {
        pdf: { data: b.data, mimeType: b.mimeType || 'application/pdf', fileName }
      },
    });
  }
}

return out.length ? out : [{ json: { hasPdf: false, success: false, message: 'Aucune sortie générée' } }];

/**
 * Parser de factures/devis français SANS LLM
 * Retourne le MÊME FORMAT que Basic LLM Chain : { text: "CSV complet" }
 */

function cleanText(text) {
  return text.replace(/\s+/g, ' ').trim();
}

function extractDate(text) {
  const datePatterns = [
    /(\d{1,2})[\/\-\.](\d{1,2})[\/\-\.](\d{4})/,
    /(\d{4})[\/\-\.](\d{1,2})[\/\-\.](\d{1,2})/
  ];
  for (const regex of datePatterns) {
    const match = text.match(regex);
    if (match) {
      if (match[3] && match[3].length === 4) {
        return `${match[3]}-${match[2].padStart(2,'0')}-${match[1].padStart(2,'0')}`;
      } else if (match[1].length === 4) {
        return `${match[1]}-${match[2].padStart(2,'0')}-${match[3].padStart(2,'0')}`;
      }
    }
  }
  return '';
}

function extractAmount(text) {
  if (!text) return 0;
  const cleaned = String(text).replace(/\s/g, '').replace(',', '.');
  const num = parseFloat(cleaned);
  return isNaN(num) ? 0 : num;
}

function detectDocumentType(text) {
  const lowerText = text.toLowerCase();
  if (lowerText.includes('avoir') || lowerText.includes('credit note')) return 'credit_note';
  if (lowerText.includes('facture') || lowerText.includes('invoice')) return 'invoice';
  if (lowerText.includes('devis') || lowerText.includes('quote')) return 'quote';
  if (lowerText.includes('reçu') || lowerText.includes('receipt')) return 'receipt';
  return 'other';
}

function extractDocumentNumber(text) {
  const patterns = [
    /(?:Facture|Invoice|Devis|Quote)\s*n°?\s*:?\s*([A-Z0-9\-\/]+)/i,
    /N°\s*(?:Facture|Invoice|Devis)?\s*:?\s*([A-Z0-9\-\/]+)/i,
    /(?:Ref|Reference|Numéro)\s*:?\s*([A-Z0-9\-\/]+)/i,
    /([A-Z]{3}\d{5,})/
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match && match[1]) return match[1].trim();
  }
  return '';
}

function extractCustomerCode(text) {
  const patterns = [
    /N°\s*client\s*:?\s*(CLT\d{8})/i,
    /Client\s*:?\s*(CLT\d{8})/i,
    /Code\s*client\s*:?\s*([A-Z0-9]+)/i,
    /(CLT\d{8})/i
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match && match[1]) return match[1].trim();
  }
  return '';
}

function extractParties(text) {
  const parties = { supplier: '', customer: '' };
  const customerPatterns = [
    /(?:Facturé à|Bill to|Client)\s*:?\s*([^\n]+(?:\n[^\n]+){0,3})/i,
    /((?:Madame|Monsieur|M\.|Mme)\s+[A-Z][^\n]+(?:\n[^\n]+){0,2})/
  ];
  for (const pattern of customerPatterns) {
    const match = text.match(pattern);
    if (match && match[1]) {
      const lines = match[1].split('\n').slice(0, 3).map(l => l.trim()).filter(l => l);
      parties.customer = lines.join(', ');
      break;
    }
  }
  const supplierPatterns = [
    /((?:SARL|SAS|SA|EURL)\s+[A-Z][^\n]+(?:\n[^\n]+){0,4})/,
    /(?:Fournisseur|Vendeur)\s*:?\s*([^\n]+(?:\n[^\n]+){0,3})/i
  ];
  for (const pattern of supplierPatterns) {
    const match = text.match(pattern);
    if (match && match[1]) {
      const lines = match[1].split('\n').slice(0, 5).map(l => l.trim()).filter(l => l);
      parties.supplier = lines.join(', ');
      break;
    }
  }
  return parties;
}

function extractProductLines(text) {
  const lines = [];
  const textLines = text.split('\n');
  const linePattern = /(.+?)\s+(\d+(?:[,\.]\d+)?)\s+.*?(\d+[,\.]\d{2})\s+.*?(\d+[,\.]\d{2})/;
  let lineNumber = 1;
  for (let i = 0; i < textLines.length; i++) {
    const line = textLines[i].trim();
    if (!line || line.toLowerCase().includes('total') || line.toLowerCase().includes('tva') || line.toLowerCase().includes('description') || line.toLowerCase().includes('quantité') || line.length < 15) continue;
    const match = line.match(linePattern);
    if (match) {
      const quantity = extractAmount(match[2]);
      const unitPrice = extractAmount(match[3]);
      const lineAmount = extractAmount(match[4]);
      if (quantity > 0 && unitPrice > 0) {
        lines.push({ lineNumber: lineNumber++, description: match[1].trim(), quantity, unit: '', unitPrice, lineAmount, vatRate: 0.10 });
      }
    }
  }
  return lines;
}

function extractTotals(text) {
  const totals = { totalHT: 0, totalVAT: 0, totalTTC: 0 };
  const htPatterns = [/Total\s+HT\s*:?\s*([\d\s,\.]+)/i, /Sous[\s-]?total\s*:?\s*([\d\s,\.]+)/i, /Montant\s+HT\s*:?\s*([\d\s,\.]+)/i];
  const vatPatterns = [/(?:TVA|VAT)\s*(?:\d+%)?\s*:?\s*([\d\s,\.]+)/i, /Montant\s+TVA\s*:?\s*([\d\s,\.]+)/i];
  const ttcPatterns = [/Total\s+TTC\s*:?\s*([\d\s,\.]+)/i, /Total\s+à\s+payer\s*:?\s*([\d\s,\.]+)/i, /Montant\s+total\s*:?\s*([\d\s,\.]+)/i, /Net\s+à\s+payer\s*:?\s*([\d\s,\.]+)/i];
  for (const p of htPatterns) { const m = text.match(p); if (m) { totals.totalHT = extractAmount(m[1]); break; } }
  for (const p of vatPatterns) { const m = text.match(p); if (m) { totals.totalVAT = extractAmount(m[1]); break; } }
  for (const p of ttcPatterns) { const m = text.match(p); if (m) { totals.totalTTC = extractAmount(m[1]); break; } }
  if (totals.totalTTC === 0 && totals.totalHT > 0) totals.totalTTC = totals.totalHT + totals.totalVAT;
  if (totals.totalVAT === 0 && totals.totalHT > 0 && totals.totalTTC > 0) totals.totalVAT = totals.totalTTC - totals.totalHT;
  return totals;
}

function escapeCSV(value) {
  if (!value) return '';
  const str = String(value);
  if (str.includes(',') || str.includes('"') || str.includes('\n')) return '"' + str.replace(/"/g, '""') + '"';
  return str;
}

const items = $input.all();
const outputItems = [];

for (const item of items) {
  const text = item.json.text || '';
  if (!text) { outputItems.push({ json: { text: '', error: 'Pas de texte extrait du PDF', success: false } }); continue; }
  try {
    const sourceType = detectDocumentType(text);
    const documentNumber = extractDocumentNumber(text);
    const documentDate = extractDate(text);
    const customerCode = extractCustomerCode(text);
    const parties = extractParties(text);
    const totals = extractTotals(text);
    let productLines = extractProductLines(text);
    if (productLines.length === 0) {
      productLines = [{ lineNumber: 1, description: 'Document sans détail de lignes', quantity: 1, unit: '', unitPrice: totals.totalHT, lineAmount: totals.totalHT, vatRate: totals.totalVAT > 0 ? (totals.totalVAT / totals.totalHT) : 0.10 }];
    }
    const csvHeader = 'source_type,document_number,document_date,valid_until,customer_code,party_customer,party_supplier,line_number,description,quantity,unit,unit_price_ht,line_amount_ht,vat_rate,currency,account_iban,balance_after,total_ht,total_vat,total_ttc,category';
    const csvLines = [csvHeader];
    for (const line of productLines) {
      csvLines.push([sourceType, documentNumber, documentDate, '', customerCode, escapeCSV(parties.customer), escapeCSV(parties.supplier), line.lineNumber, escapeCSV(line.description), line.quantity.toFixed(2), line.unit || '', line.unitPrice.toFixed(2), line.lineAmount.toFixed(2), line.vatRate.toFixed(2), 'EUR', '', '', totals.totalHT.toFixed(2), totals.totalVAT.toFixed(2), totals.totalTTC.toFixed(2), 'pellets'].join(','));
    }
    outputItems.push({ json: { text: csvLines.join('\n') } });
  } catch (error) {
    outputItems.push({ json: { text: '', error: error.message, success: false } });
  }
}

return outputItems;

/**
 * Nœud Code n8n — création csv (VERSION FILTRÉE)
 */

const DEBUG = false;
const useSemicolon = true;
const addBom = true;
const crlf = true;

const DELIM = useSemicolon ? ';' : ',';
const NL = crlf ? '\r\n' : '\n';

const RAW_TEXT_KEYS = ['text', 'output', 'response'];

const HEADERS = ['source_type','document_number','document_date','currency','customer_code','customer_name','customer_vat','supplier_name','supplier_vat','line_no','sku','description','qty','unit','unit_price_ht','discount','tax_rate','line_total_ht','total_ht','total_tva','total_ttc'];

function stripCodeFences(s) {
  if (typeof s !== 'string') return s;
  let out = s.trim();
  out = out.replace(/^```[a-zA-Z]*\s*\n/, '');
  out = out.replace(/\n```$/, '');
  return out.trim();
}

function toNum(v) {
  if (v === undefined || v === null || v === '') return null;
  const s = String(v).replace(/\s/g, '').replace(',', '.');
  const n = Number(s);
  return Number.isFinite(n) ? n : null;
}

function csvEscape(v) {
  const s = String(v ?? '');
  if (s.includes('"') || s.includes(DELIM) || s.includes('\n') || s.includes('\r')) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
}

function parseCSVLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    const nextChar = line[i + 1];
    if (char === '"') {
      if (inQuotes && nextChar === '"') { current += '"'; i++; }
      else inQuotes = !inQuotes;
    } else if ((char === ',' || char === ';') && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }
  result.push(current.trim());
  return result;
}

function parseCsvToStructured(csvText) {
  const lines = csvText.split(/\r?\n/).filter(l => l.trim());
  if (lines.length < 2) return null;
  const headers = parseCSVLine(lines[0]).map(h => h.replace(/^"|"$/g, '').trim());
  const getValueFromLine = (values, header) => { const idx = headers.indexOf(header); return idx >= 0 ? values[idx] : ''; };
  const firstLine = parseCSVLine(lines[1]);
  const customer_code = getValueFromLine(firstLine, 'customer_code');
  const customer_name_raw = getValueFromLine(firstLine, 'party_customer');
  let customer_name = customer_name_raw;
  if (customer_name_raw) { const match = customer_name_raw.match(/^([^,]+)/); if (match) customer_name = match[1].trim(); }
  const customer_vat = getValueFromLine(firstLine, 'customer_vat');
  const supplier_raw = getValueFromLine(firstLine, 'party_supplier');
  let supplier_name = supplier_raw;
  if (supplier_raw) { const match = supplier_raw.match(/^([^,]+)/); if (match) supplier_name = match[1].trim(); }
  const supplier_vat = getValueFromLine(firstLine, 'supplier_vat');
  const source_type = getValueFromLine(firstLine, 'source_type') || 'quote';
  const document_number = getValueFromLine(firstLine, 'document_number');
  const document_date = getValueFromLine(firstLine, 'document_date');
  const currency = getValueFromLine(firstLine, 'currency') || 'EUR';
  const total_ht = toNum(getValueFromLine(firstLine, 'total_ht')) ?? 0;
  const total_tva = toNum(getValueFromLine(firstLine, 'total_vat') || getValueFromLine(firstLine, 'total_tva')) ?? 0;
  const total_ttc = toNum(getValueFromLine(firstLine, 'total_ttc')) ?? 0;
  let numeroClient = customer_code || customer_vat || '';
  if (!numeroClient && customer_name) {
    const cleaned = customer_name.toUpperCase().replace(/[^A-Z0-9]/g, '').substring(0, 8).padEnd(8, 'X');
    numeroClient = 'CLT' + cleaned;
  }
  const products = [];
  for (let i = 1; i < lines.length; i++) {
    const values = parseCSVLine(lines[i]);
    const getVal = (header) => getValueFromLine(values, header);
    const qty = toNum(getVal('quantity') || getVal('qty'));
    const unit_price_ht = toNum(getVal('unit_price_ht'));
    if (qty === null || unit_price_ht === null) continue;
    let description = String(getVal('description') || '').split(/\r?\n/)[0].trim();
    description = description.replace(/\s{2,}/g, ' ');
    const line_amount = toNum(getVal('line_amount_ht')) ?? (qty * unit_price_ht);
    const tax_rate = toNum(getVal('vat_rate') || getVal('tax_rate')) ?? 0;
    products.push({ type: 'product', document_number, line_no: parseInt(getVal('line_number')) || i, sku: getVal('sku'), description, qty, unit: getVal('unit'), unit_price_ht, discount: toNum(getVal('discount')) ?? 0, tax_rate, line_total_ht: line_amount });
  }
  return { client: { type: 'client', source_type, document_number, document_date, currency, customer_code, customer_name, customer_vat, supplier_name, supplier_vat, NumeroClient: numeroClient, total_ht, total_tva, total_ttc }, products };
}

const items = $input.all();
const out = [];

for (const it of items) {
  const j = it.json || {};
  let rawText = '';
  for (const k of RAW_TEXT_KEYS) { if (typeof j[k] === 'string' && j[k].trim()) { rawText = j[k]; break; } }
  if (!rawText) continue;
  const cleaned = stripCodeFences(rawText);
  const structured = parseCsvToStructured(cleaned);
  if (!structured) { out.push({ json: { error: 'Unable to parse CSV', rawPreview: rawText.substring(0, 300) } }); continue; }
  if (!structured.products.length) { out.push({ json: { error: 'Aucune ligne produit valide', doc: structured.client.document_number || '' } }); continue; }
  const csvRows = [HEADERS.map(csvEscape).join(DELIM)];
  for (const prod of structured.products) {
    const row = { source_type: structured.client.source_type, document_number: structured.client.document_number, document_date: structured.client.document_date, currency: structured.client.currency, customer_code: structured.client.customer_code, customer_name: structured.client.customer_name, customer_vat: structured.client.customer_vat, supplier_name: structured.client.supplier_name, supplier_vat: structured.client.supplier_vat, line_no: prod.line_no, sku: prod.sku, description: prod.description, qty: prod.qty, unit: prod.unit, unit_price_ht: prod.unit_price_ht, discount: prod.discount, tax_rate: prod.tax_rate, line_total_ht: prod.line_total_ht, total_ht: structured.client.total_ht, total_tva: structured.client.total_tva, total_ttc: structured.client.total_ttc };
    csvRows.push(HEADERS.map(h => csvEscape(row[h] ?? '')).join(DELIM));
  }
  let payload = csvRows.join(NL) + NL;
  if (addBom) payload = '\uFEFF' + payload;
  const data = Buffer.from(payload, 'utf8').toString('base64');
  const fileName = `${structured.client.source_type}_${structured.client.document_number || 'doc'}.csv`;
  out.push({ json: { ...structured.client, ok: true, fileName, nb_products: structured.products.length }, binary: { file: { data, mimeType: 'text/csv', fileName, fileExtension: 'csv' } } });
  structured.products.forEach((product, idx) => {
    out.push({ json: { ...product, ok: true, parent_document: structured.client.document_number, parent_customer: structured.client.NumeroClient, parent_customer_code: structured.client.customer_code, product_index: idx + 1 } });
  });
}

return out;

/**
 * Fusionner les données du PDF + Contact Airtable
 */
const items = $input.all();
const out = [];
for (const item of items) {
  const j = item.json || {};
  const contactId = j.id || null;
  const contactFields = j.fields || {};
  const NumeroClient = j.NumeroClient || contactFields['code contact'] || '';
  const document_number = j.document_number || '';
  const document_date = j.document_date || '';
  const total_ttc = j.total_ttc || 0;
  const currency = j.currency || 'EUR';
  const party_customer = j.party_customer || j.customer_name || '';
  out.push({
    json: {
      client_key: contactId,
      contactId: contactId,
      NumeroClient: NumeroClient,
      document_number: document_number,
      document_date: document_date,
      total_ttc: parseFloat(String(total_ttc).replace(',', '.')) || 0,
      currency: currency,
      customer_name: party_customer,
      _contactFound: !!contactId,
      _contactName: contactFields.Name || contactFields['code contact'] || '',
      _hasNumeroClient: !!j.NumeroClient,
      _hasDocNumber: !!j.document_number
    },
    binary: item.binary
  });
}
return out;

const toNum = (v, def = undefined) => { if (v === null || v === undefined || v === '') return def; const s = String(v).replace(/\s| /g, '').replace(/,(?=\d{1,2}(?!\d))/g, '.'); const n = Number(s.replace(/[^0-9.\-]/g, '')); return Number.isFinite(n) ? n : def; };
const toISODate = (d, def = undefined) => { if (!d) return def; const s = String(d).trim(); const m = s.match(/^(\d{2})\/(\d{2})\/(\d{4})$/); if (m) return `${m[3]}-${m[2]}-${m[1]}`; const dt = new Date(s); if (!isNaN(dt.getTime())) return dt.toISOString().slice(0,10); return def; };
const str = (v, def = undefined) => { if (v === null || v === undefined) return def; const s = String(v).trim(); return s.length ? s : def; };
const joiner = ', ';
function normalizeProductLine(src, defaults) { const libelle = str(src.libelle) ?? str(src.description) ?? `Produit ${src.product_index ?? ''}`.trim(); const qty = toNum(src.quantite) ?? toNum(src.qty) ?? 1; const unitHT = toNum(src.prix_unitaire_ht ?? src.unit_price_ht); const totalHT = toNum(src.total_ht); const totalTVA = toNum(src.total_tva); const totalTTC = toNum(src.total_ttc); const tvaRate = toNum(src.taux_tva ?? src.vat_rate); return { Produits: libelle, Nombres: qty, unit_price_ht_num: unitHT, total_ht_num: totalHT, total_tva_num: totalTVA, total_ttc_num: totalTTC, tva_rate_num: tvaRate, document_date_iso: defaults.document_date_iso, document_id: defaults.document_id }; }
const incoming = $input.all();
const groups = new Map();
for (let idx = 0; idx < incoming.length; idx++) { const src = incoming[idx].json || {}; const documentId = str(src.NumeroDocument) ?? str(src.document_number) ?? str(src.parent_document) ?? 'Sans numéro'; const documentDateISO = toISODate(src.document_date) ?? toISODate(src.DateDocument) ?? toISODate(src.date); if (!groups.has(documentId)) { groups.set(documentId, { meta: { document_id: documentId, document_date_iso: documentDateISO }, lines: [] }); } const g = groups.get(documentId); if (!g.meta.document_date_iso && documentDateISO) g.meta.document_date_iso = documentDateISO; if (Array.isArray(src.Produits) && src.Produits.length) { for (let i = 0; i < src.Produits.length; i++) { g.lines.push(normalizeProductLine(src.Produits[i] || {}, { document_date_iso: g.meta.document_date_iso, document_id: documentId })); } continue; } const isProductLine = src.type === 'product' || src.description != null || src.qty != null || src.product_index != null; if (isProductLine) g.lines.push(normalizeProductLine(src, { document_date_iso: g.meta.document_date_iso, document_id: documentId })); }
const out = [];
for (const [docId, group] of groups.entries()) { const L = group.lines; if (!L.length) continue; const concat = (arr) => arr.map(v => v == null ? '' : String(v)).join(joiner); out.push({ json: { "Commandes Clients": docId, "Produits": concat(L.map(l => l.Produits)), "Nombres": concat(L.map(l => l.Nombres)), "unit_price_ht_num": concat(L.map(l => l.unit_price_ht_num ?? '')), "total_ht_num": concat(L.map(l => l.total_ht_num ?? '')), "total_tva_num": concat(L.map(l => l.total_tva_num ?? '')), "total_ttc_num": concat(L.map(l => l.total_ttc_num ?? '')), "tva_rate_num": concat(L.map(l => l.tva_rate_num ?? '')), "document_date_iso": group.meta.document_date_iso } }); }
return out;

